import React from "react";

export default function Home() {
  return (
    <section className="hero">
      <p className="hero__eyebrow">Fall registration is open</p>
      <h1 className="hero__title">Welcome to ABC University</h1>
      <p className="hero__subtitle">
        Register for your student account, sign in, and enroll in this term's
        course catalog — all from one place.
      </p>
    </section>
  );
}
